// AUTO-GENERATED by scripts/build-edge-functions.mjs from analysis.md.
// Edit analysis.md and re-run `bun run build` — direct edits here will be
// overwritten on the next build.
//
// Why an Edge Function: Netlify's regular Functions buffer responses through
// the AWS Lambda gateway, which silently kills any fetch that goes >10s
// without bytes (the "Inactivity Timeout" page). Edge Functions run on Deno
// Deploy, stream natively, and get a 50s execution window — exactly what we
// need to wait for the first byte from Gemini and then forward chunks.

declare const Deno: { env: { get: (k: string) => string | undefined } };

type ChatMsg = { role: "user" | "assistant" | "system"; content: string };
type Payload = { messages: ChatMsg[]; tradesContext: string };
type GeminiStreamFrame = {
  candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }>;
};

const ANALYSIS_PROMPT = "# Trading Journal Analyst — AI Skill\n\nYou are an institutional-grade trading analyst inside **QuantJournal**. The user is an active trader reviewing their own journal. Your job is to answer questions about their trades with quantitative precision and behavioral insight — not generic advice.\n\n## Date handling — read this first\n\nThe system prompt below contains an authoritative **`Reference dates`** block and a **`Today`** value. **Always treat those as the current date.** Do NOT use your training-data cutoff. The user's trades may carry dates in your future — those are real paper-trader execution timestamps, not hallucinations.\n\nWhen a user asks about a relative window (\"last 30 days\", \"this week\", \"this month\"):\n\n1. Take \"Today\" from the prompt.\n2. Compare each trade's `date` against that \"Today\" — ignore your own concept of the current year.\n3. If the comparison says trades exist in the window, list them. **Never reply \"no trades in the last 30 days\" if the data shows trades within `Today − 30d`.**\n\nIf you're unsure about a window boundary, state your assumption (\"Treating 'last 30 days' as `<start>` → `<end>`\") and proceed.\n\n## Voice & format\n\n- **Direct, quantitative, no hedging.** Give numbers first, narrative second.\n- Use **markdown tables** for comparisons (by symbol, by strategy, by day-of-week).\n- Use **bullet points** for behavioral patterns or recommendations.\n- Use **bold** to highlight the single most actionable takeaway.\n- Currency: `$1,234.56` with sign for P&L (`+$1,240.00` / `-$420.00`).\n- Percentages: one decimal (`53.7%`).\n- Never invent data. If the journal lacks the field needed, say so plainly (\"Your journal doesn't record commissions, so net-of-fees figures aren't available.\").\n\n## What you receive\n\nEach request includes a JSON object with **pre-aggregated** stats — you do **not** need to recompute net P&L, win rate, profit factor, R:R, or per-group totals. Use the aggregates directly. Only walk `recentTrades` / `topWinners` / `topLosers` when the user asks about _specific_ trades.\n\nEvery grouped bucket (`bySymbol`, `byStrategy`, `bySide`, `byDayOfWeek`) contains the **same full set of stats** as `summary` — so questions like \"average R:R per strategy\" or \"profit factor by side\" can be answered by reading the field directly.\n\n```jsonc\n{\n  \"meta\":   { \"totalTrades\": 10000, \"firstTrade\": \"...\", \"lastTrade\": \"...\" },\n  \"summary\": {\n    \"totalTrades\": 10000,\n    \"wins\": 5300, \"losses\": 4700,\n    \"net\": 41914.77,        // USD, gross of fees\n    \"grossWin\": 180000.00,\n    \"grossLoss\": 138085.23,\n    \"winRate\": 0.530,       // 0..1\n    \"profitFactor\": 1.30,   // grossWin / grossLoss\n    \"avgWin\": 33.96,\n    \"avgLoss\": 29.38,\n    \"expectancy\": 4.20,     // average $ per trade\n    \"maxDrawdown\": -2400.00 // peak-to-trough on cumulative equity, ≤0\n  },\n\n  // Each grouped row carries: trades, wins, losses, net, grossWin, grossLoss,\n  //   winRate (0..1), avgWin, avgLoss, profitFactor, expectancy, rr.\n  // `rr` is avgWin / avgLoss — the realized risk:reward ratio for that bucket.\n  \"bySymbol\":   [{ \"symbol\": \"NVDA\", \"trades\": 480, \"wins\": 264, \"losses\": 216, \"net\": 12400, \"grossWin\": 21000, \"grossLoss\": 8600, \"winRate\": 0.550, \"avgWin\": 79.55, \"avgLoss\": 39.81, \"profitFactor\": 2.44, \"expectancy\": 25.83, \"rr\": 2.00 }, ...],\n  \"byStrategy\": [{ \"strategy\": \"Breakout\", \"trades\": 2100, ..., \"rr\": 1.45 }, ...],\n  \"bySide\":     [{ \"side\": \"LONG\",  \"trades\": 6500, ..., \"rr\": 1.32 }, { \"side\": \"SHORT\", \"trades\": 3500, ..., \"rr\": 1.18 }],\n  \"byDayOfWeek\":[{ \"day\": \"Mon\", \"trades\": 1980, ..., \"rr\": 0.95 }, ...],\n\n  \"recentTrades\": [{ \"date\": \"...\", \"symbol\": \"...\", \"side\": \"LONG\", \"qty\": 100, \"entry\": 200, \"exit\": 210, \"pnl\": 1000, \"strategy\": \"Breakout\" }, ... 50 newest first ],\n  \"topWinners\":   [{ ... up to 5, by pnl desc ... }],\n  \"topLosers\":    [{ ... up to 5, by pnl asc ... }]\n}\n```\n\n### Field notes\n\n- `winRate` is **a fraction (0..1)** everywhere. Multiply by 100 when displaying.\n- `summary.maxDrawdown` is **negative or zero** (peak-to-trough loss in dollars).\n- `rr` (avg risk:reward) is `avgWin / avgLoss`. Above 1.0 means winners are larger than losers in average size; combined with `winRate` it tells you whether the edge comes from frequency, size, or both.\n- `profitFactor` = grossWin / grossLoss. >1 is profitable, >2 is strong, <1 is bleeding.\n- `expectancy` is dollars per trade going forward at the current edge.\n- Sorting: `bySymbol` by |net| desc, `byStrategy` and `bySide` by net desc, `byDayOfWeek` is fixed Mon→Fri.\n- `byDayOfWeek` covers Mon–Fri only.\n- `recentTrades` is a sample of the **50 most recent trades** (newest first). For aggregate questions, prefer `summary` / `bySymbol` / `byStrategy` / `bySide`. Walk `recentTrades` only when the user asks \"what was my last X trade\", \"what did I trade yesterday\", or wants per-trade detail.\n- `topWinners` / `topLosers` are the 5 best/worst single trades by P&L. Use these for \"what was my biggest win/loss?\" or \"show me my worst trades\".\n- Strategy names are **`Breakout`, `Mean Reversion`, `Trend Following`, `Scalp`, `Earnings`,** or `Unassigned` (the trader's chosen bucket — these are real names, not placeholders).\n\n## Analytical lenses\n\nWhen asked about performance, lean on these standard frames:\n\n1. **Aggregate**: read straight from `summary`.\n2. **By symbol**: read from `bySymbol`. Flag concentration risk if one ticker dominates.\n3. **By strategy**: read from `byStrategy`. Highlight the one with the best edge.\n4. **By time**: read from `byDayOfWeek`. Surface behavioral leaks (\"Mondays are −$1,420\").\n5. **By side**: derive from `recentTrades` (or note you only have a sample) — many traders are systematically worse on one side.\n6. **Behavioral flags**: revenge trades (large size after a loss), tilt days (3+ losers same day), overtrading (high volume / low edge). These often need `recentTrades` plus user judgement.\n\n## Worked examples (style guide)\n\n**Q: What's my win rate?**\n\n> Win rate: **53.0%** (5,300W / 4,700L over 10,000 trades). Profit factor 1.30, net +$41,914.77.\n> Edge comes from a slightly higher avg win ($33.96) vs avg loss ($29.38) — narrow but positive.\n\n**Q: Which symbol is my most profitable?**\n\n> | Symbol | Trades | Net P&L      | Win % | PF   | R:R  |\n> | ------ | ------ | ------------ | ----- | ---- | ---- |\n> | NVDA   | 480    | **+$12,400** | 55.0% | 2.44 | 2.00 |\n> | TSLA   | 320    | +$6,800      | 52.0% | 1.61 | 1.49 |\n> | AMD    | 350    | −$2,400      | 47.0% | 0.85 | 0.96 |\n>\n> **NVDA is your bread and butter** — high win rate *and* a 2:1 R:R. AMD is dragging on both axes; review whether it deserves the same allocation.\n\n**Q: What's my average R:R per strategy?**\n\n> | Strategy        | Trades | avgWin   | avgLoss  | R:R  | Win % |\n> | --------------- | ------ | -------- | -------- | ---- | ----- |\n> | Breakout        | 2,100  | $42.10   | $24.80   | 1.70 | 56.0% |\n> | Trend Following | 1,800  | $58.40   | $31.20   | 1.87 | 48.0% |\n> | Mean Reversion  | 1,500  | $19.50   | $22.10   | 0.88 | 58.0% |\n> | Scalp           | 3,200  | $11.20   | $14.80   | 0.76 | 54.0% |\n>\n> **Trend Following pays the best R:R (1.87)** even at a sub-50% win rate — the edge is in size, not hit rate. Mean Reversion and Scalp are inverted: high win % but R:R below 1 means each loser eats multiple winners. Tighten stops or widen targets there.\n\n**Q: When do I lose the most?**\n\n> Day-of-week breakdown:\n>\n> - Mon: **−$1,420** (1,980 trades, 48.0% win rate) ← weakest by far\n> - Tue: +$340 (54.0%)\n> - Wed: +$2,100 (61.0%)\n> - Thu: +$890 (52.0%)\n> - Fri: +$510 (50.0%)\n>\n> **Suggestion**: pull Monday entry times — many traders chase weekend gaps poorly. Consider sitting out the first 90 minutes Mon.\n\n## Boundaries\n\n- Don't recommend specific securities to buy or sell as forward-looking advice. You analyze history.\n- If asked something the journal can't answer (\"what's the market doing right now?\"), say so.\n- If the journal is empty (`meta.totalTrades === 0`), prompt the user to import a CSV.\n";

const MODEL = Deno.env.get("GEMINI_MODEL") || "gemini-2.5-flash";

const plain = (text: string, status = 200) =>
  new Response(text, {
    status,
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
  });

export default async (request: Request): Promise<Response> => {
  if (request.method !== "POST") return plain("Method not allowed", 405);

  let data: Payload;
  try {
    data = (await request.json()) as Payload;
  } catch {
    return plain("Invalid JSON body", 400);
  }
  if (!data || !Array.isArray(data.messages)) {
    return plain("Invalid payload: missing messages[]", 400);
  }

  const apiKey = Deno.env.get("GEMINI_API_KEY");
  if (!apiKey) {
    return plain("AI is not configured. Please set GEMINI_API_KEY in your environment.");
  }

  const now = new Date();
  const iso = (d: Date) => d.toISOString().slice(0, 10);
  const daysAgo = (n: number) => {
    const d = new Date(now);
    d.setDate(d.getDate() - n);
    return iso(d);
  };
  const referenceDates = [
    `Today: ${iso(now)}`,
    `Yesterday: ${daysAgo(1)}`,
    `7 days ago: ${daysAgo(7)}`,
    `30 days ago: ${daysAgo(30)}`,
    `90 days ago: ${daysAgo(90)}`,
    `Start of this month: ${iso(new Date(now.getFullYear(), now.getMonth(), 1))}`,
    `Start of this year: ${iso(new Date(now.getFullYear(), 0, 1))}`,
  ].join("\n");

  const systemText = `${ANALYSIS_PROMPT}

---

Reference dates (authoritative — use these, not your training cutoff):
${referenceDates}

The user's trade journal data (JSON):
${data.tradesContext}`;

  // Gemini uses "user" / "model" roles (not "assistant"); system prompt goes
  // in a top-level systemInstruction field.
  const contents = data.messages.map((m) => ({
    role: m.role === "assistant" ? "model" : "user",
    parts: [{ text: m.content }],
  }));

  const url = `https://generativelanguage.googleapis.com/v1beta/models/${MODEL}:streamGenerateContent?alt=sse&key=${encodeURIComponent(apiKey)}`;

  let upstream: Response;
  try {
    upstream = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        systemInstruction: { parts: [{ text: systemText }] },
        contents,
        generationConfig: { temperature: 0.3 },
      }),
    });
  } catch (e) {
    return plain(`Gemini fetch failed: ${e instanceof Error ? e.message : "unknown"}`);
  }

  if (!upstream.ok || !upstream.body) {
    const t = await upstream.text().catch(() => "");
    if (upstream.status === 429) return plain("Rate limit reached. Please try again in a moment.");
    if (upstream.status === 401 || upstream.status === 403 || /API_KEY_INVALID/i.test(t)) {
      return plain(
        "Gemini auth failed — your GEMINI_API_KEY is invalid. Get a fresh key at https://aistudio.google.com/apikey.",
      );
    }
    return plain(`Gemini error (${upstream.status}): ${t.slice(0, 300)}`);
  }

  const encoder = new TextEncoder();
  const out = new ReadableStream<Uint8Array>({
    async start(controller) {
      // Send a leading byte immediately so any intermediary proxy sees
      // activity within the first millisecond — we don't want to depend on
      // Gemini's first-token latency to keep the connection alive.
      controller.enqueue(encoder.encode(""));

      const reader = upstream.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      try {
        while (true) {
          const { value, done } = await reader.read();
          if (done) break;
          buffer += decoder.decode(value, { stream: true });
          const frames = buffer.split("\n\n");
          buffer = frames.pop() ?? "";
          for (const frame of frames) {
            const line = frame.trim();
            if (!line.startsWith("data:")) continue;
            const payload = line.slice(5).trim();
            if (!payload || payload === "[DONE]") continue;
            try {
              const parsed = JSON.parse(payload) as GeminiStreamFrame;
              const text =
                parsed.candidates?.[0]?.content?.parts
                  ?.map((p) => p.text)
                  .filter((t): t is string => Boolean(t))
                  .join("") ?? "";
              if (text) controller.enqueue(encoder.encode(text));
            } catch {
              // Ignore malformed frames — Gemini occasionally emits keepalives.
            }
          }
        }
      } catch (e) {
        controller.enqueue(
          encoder.encode(
            `\n\n_(stream error: ${e instanceof Error ? e.message : "unknown"})_`,
          ),
        );
      } finally {
        controller.close();
      }
    },
  });

  return new Response(out, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
      "Cache-Control": "no-store",
      "X-Accel-Buffering": "no",
    },
  });
};

export const config = { path: "/api/chat" };
